defmodule YourAppWeb.ProductController do
  use YourAppWeb, :controller
  
  import Ecto.Query
  alias YourApp.Repo
  alias YourApp.Product

  def search(conn, params) do
    search_term = Map.get(params, "search", "")
    min_price = Map.get(params, "min_price")
    max_price = Map.get(params, "max_price")
    category = Map.get(params, "category")
    in_stock = Map.get(params, "in_stock")
    sort_by = Map.get(params, "sort_by", "name")
    order = Map.get(params, "order", "asc")

    products = 
      from(p in Product)
      |> apply_search_filter(search_term)
      |> apply_price_filter(min_price, max_price)
      |> apply_category_filter(category)
      |> apply_stock_filter(in_stock)
      |> apply_sorting(sort_by, order)
      |> Repo.all()

    json(conn, %{products: products, count: length(products)})
  end

  defp apply_search_filter(query, "") do
    query
  end

  defp apply_search_filter(query, search_term) do
    from(p in query, where: fragment("name LIKE ?", ^"%#{search_term}%"))
  end

  defp apply_price_filter(query, nil, nil), do: query

  defp apply_price_filter(query, min_price, nil) when not is_nil(min_price) do
    from(p in query, where: fragment("price >= ?", ^min_price))
  end

  defp apply_price_filter(query, nil, max_price) when not is_nil(max_price) do
    from(p in query, where: fragment("price <= ?", ^max_price))
  end

  defp apply_price_filter(query, min_price, max_price) do
    from(p in query, where: fragment("price BETWEEN ? AND ?", ^min_price, ^max_price))
  end

  defp apply_category_filter(query, nil), do: query

  defp apply_category_filter(query, category) do
    from(p in query, where: fragment("category = ?", ^category))
  end

  defp apply_stock_filter(query, nil), do: query

  defp apply_stock_filter(query, "true") do
    from(p in query, where: fragment("stock > 0"))
  end

  defp apply_stock_filter(query, _), do: query

  defp apply_sorting(query, sort_by, order) do
    order_direction = if order == "desc", do: :desc, else: :asc
    
    case sort_by do
      "price" ->
        from(p in query, order_by: [{^order_direction, fragment("price")}])
      "created_at" ->
        from(p in query, order_by: [{^order_direction, fragment("inserted_at")}])
      "stock" ->
        from(p in query, order_by: [{^order_direction, fragment("stock")}])
      _ ->
        from(p in query, order_by: [{^order_direction, fragment("name")}])
    end
  end

  def advanced_search(conn, params) do
    search_term = Map.get(params, "search", "")
    
    products = 
      from(p in Product,
        where: fragment("name LIKE '%#{search_term}%' OR description LIKE '%#{search_term}%'"))
      |> Repo.all()

    json(conn, %{products: products})
