  def fuzzy_search(conn, %{"search" => search_term}) do
    products = 
      from(p in Product,
        where: fragment("LOWER(name) LIKE LOWER(?)", ^"%#{search_term}%"),
        or_where: fragment("LOWER(description) LIKE LOWER(?)", ^"%#{search_term}%"))
      |> Repo.all()

    json(conn, %{products: products})
  end

  def full_text_search(conn, %{"search" => search_term}) do
    products = 
      from(p in Product,
        where: fragment("to_tsvector('english', name || ' ' || description) @@ plainto_tsquery('english', ?)", ^search_term),
        order_by: fragment("ts_rank(to_tsvector('english', name || ' ' || description), plainto_tsquery('english', ?)) DESC", ^search_term))
      |> Repo.all()

    json(conn, %{products: products})
  end
